import{_ as e,o as a,c as r,a3 as o}from"./chunks/framework.BRHnm6VC.js";const u=JSON.parse('{"title":"Exam Preparation","description":"","frontmatter":{"layout":"page","title":"Exam Preparation","permalink":"/exam-preparation/","nav_order":10,"has_children":true},"headers":[],"relativePath":"exam-preparation/index.md","filePath":"exam-preparation/index.md"}'),i={name:"exam-preparation/index.md"};function d(n,t,s,l,p,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="exam-preparation" tabindex="-1">Exam Preparation <a class="header-anchor" href="#exam-preparation" aria-label="Permalink to &quot;Exam Preparation&quot;">​</a></h1><p>This section helps you prepare specifically for IT examinations — strategies, practice questions, and topic-by-topic breakdowns.</p><h2 id="the-grade-12-it-exam-structure" tabindex="-1">The Grade 12 IT exam structure <a class="header-anchor" href="#the-grade-12-it-exam-structure" aria-label="Permalink to &quot;The Grade 12 IT exam structure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper</th><th>Type</th><th>Duration</th><th>Marks</th><th>Focus</th></tr></thead><tbody><tr><td>Paper 1</td><td>Practical</td><td>3 hours</td><td>150</td><td>Solution Development (programming + SQL)</td></tr><tr><td>Paper 2</td><td>Theory</td><td>3 hours</td><td>150</td><td>All five theory topics</td></tr><tr><td>PAT</td><td>Project</td><td>Ongoing</td><td>100</td><td>Software development task</td></tr></tbody></table><h2 id="paper-2-—-theory-topics" tabindex="-1">Paper 2 — Theory topics <a class="header-anchor" href="#paper-2-—-theory-topics" aria-label="Permalink to &quot;Paper 2 — Theory topics&quot;">​</a></h2><p>Paper 2 covers one question per CAPS topic:</p><table tabindex="0"><thead><tr><th>Question</th><th>Topic</th></tr></thead><tbody><tr><td>1</td><td>Systems Technologies</td></tr><tr><td>2</td><td>Communication Technologies</td></tr><tr><td>3</td><td>Internet Technologies</td></tr><tr><td>4</td><td>Data and Information Management</td></tr><tr><td>5</td><td>Social Implications</td></tr><tr><td>6</td><td>Integrated/Solution Development concepts</td></tr></tbody></table><p>To revise each topic, go to the topic page directly — each page has a <strong>Paper Connection</strong> section and <strong>Practice Questions</strong>.</p><h2 id="cognitive-levels" tabindex="-1">Cognitive levels <a class="header-anchor" href="#cognitive-levels" aria-label="Permalink to &quot;Cognitive levels&quot;">​</a></h2><p>Both papers test content at three levels:</p><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>% of marks</th></tr></thead><tbody><tr><td>Lower order</td><td>Recall — definitions, naming, listing</td><td>±30%</td></tr><tr><td>Middle order</td><td>Application — explain, compare, describe how</td><td>±40%</td></tr><tr><td>Higher order</td><td>Analysis — evaluate, recommend with justification</td><td>±30%</td></tr></tbody></table><h2 id="general-exam-strategies" tabindex="-1">General exam strategies <a class="header-anchor" href="#general-exam-strategies" aria-label="Permalink to &quot;General exam strategies&quot;">​</a></h2><ul><li>Start revision at least 6–8 weeks before the exam</li><li>For Paper 2: practise writing full sentences, not just bullet points</li><li>For Paper 1: practise typing code regularly — speed and accuracy matter</li><li>Work through the <strong>Practice Questions</strong> on each topic page</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="./paper1-guide.html">Paper 1 Preparation Guide</a></li></ul>',15)])])}const m=e(i,[["render",d]]);export{u as __pageData,m as default};
